// Generated by OrchestKit Claude Plugin
// Created: 2026-07-10 — #2475 single-file payload re-architecture

/**
 * Session Rules Audit — SessionStart (whole-set instruction handlers, #2475)
 *
 * The whole-set handlers formerly on InstructionsLoaded fundamentally need
 * the FULL rule set at once, which the (single-file) InstructionsLoaded
 * event cannot supply. At SessionStart the full rule set exists on disk AND
 * additionalContext is honored (SessionStart is in output-guard's
 * EVENTS_WITH_ADDITIONAL_CONTEXT), so the audit reads the rules from disk
 * and runs:
 * 1. Priority Map     — make CLAUDE.md > rules precedence explicit
 * 2. Drift Detection  — compare rule hashes to last session
 * 3. Content Dedup    — detect overlapping content across files
 * 4. Rule Conflicts   — data-driven contradiction detection
 * 5. Deferred Debt    — surface ork-debt markers as a ledger (#2457)
 */

import { existsSync, readdirSync, readFileSync, statSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, outputSessionStartContext } from '../lib/common.js';
import { getProjectDir } from '../lib/common.js';
import type { LoadedFile } from './types.js';
import { priorityMap } from './priority-map.js';
import { driftDetection } from './drift-detection.js';
import { contentDedupScanner } from './content-dedup.js';
import { ruleConflictDetector } from './rule-conflicts.js';
import { debtSurfacer } from './debt-surfacer.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'session-rules-audit';
const MAX_FILES = 100;

type Handler = (files: LoadedFile[], contents: Map<string, string>) => string | null;

const HANDLERS: Array<{ name: string; fn: Handler }> = [
  { name: 'Priority Map', fn: priorityMap },
  { name: 'Drift Detection', fn: driftDetection },
  { name: 'Content Dedup', fn: contentDedupScanner },
  { name: 'Rule Conflicts', fn: ruleConflictDetector },
  { name: 'Deferred Debt', fn: debtSurfacer },
];

/**
 * Collect the instruction rule set from disk: <project>/CLAUDE.md plus
 * every .md under <project>/.claude/rules/.
 */
export function collectRuleFiles(projectDir: string): string[] {
  const paths: string[] = [];

  const claudeMd = join(projectDir, 'CLAUDE.md');
  if (existsSync(claudeMd)) paths.push(claudeMd);

  const rulesDir = join(projectDir, '.claude', 'rules');
  try {
    const entries = readdirSync(rulesDir).filter(f => f.endsWith('.md')).sort();
    for (const f of entries) paths.push(join(rulesDir, f));
  } catch {
    // No rules dir — CLAUDE.md alone is still a valid set
  }

  return paths.slice(0, MAX_FILES);
}

export function sessionRulesAudit(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const projectDir = input.project_dir || getProjectDir();
  const paths = collectRuleFiles(projectDir);

  if (paths.length === 0) {
    ctx.log(HOOK_NAME, 'No instruction files found on disk, skipping');
    return outputSilentSuccess();
  }

  const files: LoadedFile[] = [];
  const contents = new Map<string, string>();

  for (const p of paths) {
    let byte_size = 0;
    try {
      byte_size = statSync(p).size;
      contents.set(p, readFileSync(p, 'utf8'));
    } catch {
      // Skip unreadable files from the content cache, keep the path entry
    }
    files.push({ path: p, byte_size });
  }

  ctx.log(HOOK_NAME, `Auditing ${files.length} instruction files from disk`);

  const contextParts: string[] = [];

  for (const handler of HANDLERS) {
    try {
      const result = handler.fn(files, contents);
      if (result) contextParts.push(result);
    } catch (err) {
      ctx.log(HOOK_NAME, `${handler.name} failed: ${err}`, 'warn');
    }
  }

  if (contextParts.length === 0) {
    ctx.log(HOOK_NAME, 'All handlers silent');
    return outputSilentSuccess();
  }

  ctx.log(HOOK_NAME, `Consolidated ${contextParts.length} handler outputs`);
  // additionalContext IS honored on SessionStart (output-guard allowlist);
  // outputSessionStartContext stamps hookEventName:'SessionStart' (CC >=2.1.150
  // rejects SessionStart hookSpecificOutput without it).
  return outputSessionStartContext(contextParts.join('\n\n'));
}
